parameters.jsCode:
const kpis = $('Récupérer KPIs du jour').first().json;
const rdvs = $('Récupérer RDV du jour').all().map(i => i.json);
const leadsChauds = $('Récupérer leads chauds').all().map(i => i.json);
const analyseIA = $input.first().json.message.content;
const date = new Date().toLocaleDateString('fr-FR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const rdvList = rdvs.length > 0
  ? rdvs.map(r => `  • ${new Date(r.date_debut).toLocaleTimeString('fr-FR', {hour:'2-digit', minute:'2-digit'})} – ${r.titre} (${r.prenom} ${r.nom}, ${r.entreprise})`).join('\n')
  : '  Aucun RDV prévu aujourd\'hui';

const leadsChaudsList = leadsChauds.length > 0
  ? leadsChauds.map(l => `  • ${l.prenom} ${l.nom} (${l.entreprise}) – Score: ${l.score}/100`).join('\n')
  : '  Aucun lead chaud en ce moment';

return {
  date,
  kpis,
  rdvs,
  leads_chauds: leadsChauds,
  analyse_ia: analyseIA,
  rapport_discord: `📊 **BRIEFING DIRECTION – ${date}**\n\n${analyseIA}\n\n📅 **RDV du jour (${rdvs.length}) :**\n${rdvList}\n\n🔥 **Leads chauds :**\n${leadsChaudsList}\n\n💰 **CA mois en cours :** ${Number(kpis.ca_mois || 0).toLocaleString('fr-FR')}€\n⚡ **Pipeline devis :** ${Number(kpis.pipeline_devis || 0).toLocaleString('fr-FR')}€\n⚠️ **Impayés :** ${Number(kpis.impayes_total || 0).toLocaleString('fr-FR')}€`
};
